import React, { useState, useRef } from 'react'
import { useApp } from '../context/AppContext'
import MultiUploadModal from './MultiUploadModal'
import { FileUp, AlertCircle } from 'lucide-react'

const ALLOWED_EXTENSIONS = [
  '.dd', '.raw', '.img', '.e01', '.ewf', '.vdi', '.vmdk',
  '.mem', '.dmp', '.dump',
  '.log', '.txt', '.syslog', '.evtx',
  '.pcap', '.pcapng',
  '.zip', '.tar', '.gz',
]

export default function UploadZone() {
  const { submitFile, createCase, addJobToCase } = useApp()
  const [isDragging, setIsDragging] = useState(false)
  const [error, setError] = useState(null)
  const [uploading, setUploading] = useState(false)
  const [pendingFiles, setPendingFiles] = useState(null)
  const fileRef = useRef(null)

  // Einzelne Datei direkt hochladen (wie bisher)
  const handleSingleFile = async (file) => {
    if (!file) return
    setError(null)
    setUploading(true)
    try {
      await submitFile(file)
    } catch (err) {
      setError(err.message)
    } finally {
      setUploading(false)
    }
  }

  // Mehrere Dateien hochladen (mit optionaler Case-Erstellung)
  const handleMultiUpload = async (files, caseInfo) => {
    setError(null)
    setUploading(true)
    try {
      const jobIds = []
      for (const file of files) {
        const job = await submitFile(file)
        jobIds.push(job.job_id)
      }

      // Fall erstellen und alle Jobs zuordnen
      if (caseInfo) {
        const newCase = createCase({
          case_name: caseInfo.case_name,
          case_number: caseInfo.case_number || '',
        })
        for (const jobId of jobIds) {
          addJobToCase(newCase.case_id, jobId)
        }
      }
    } catch (err) {
      setError(err.message)
    } finally {
      setUploading(false)
      setPendingFiles(null)
    }
  }

  // Files verarbeiten — 1 Datei: direkt, mehrere: Modal
  const handleFiles = (fileList) => {
    if (!fileList || fileList.length === 0) return
    // FileList ist eine Live-Referenz zum DOM — wird leer wenn input.value='' gesetzt wird.
    // Deshalb hier in ein echtes Array kopieren.
    const files = Array.from(fileList)
    if (files.length === 1) {
      handleSingleFile(files[0])
    } else {
      setPendingFiles(files)
    }
  }

  const onDrop = (e) => {
    e.preventDefault()
    setIsDragging(false)
    handleFiles(e.dataTransfer.files)
  }

  return (
    <div className="p-3">
      <div
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true) }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={onDrop}
        onClick={() => fileRef.current?.click()}
        className={`
          relative flex flex-col items-center justify-center gap-2 p-4
          border-2 border-dashed rounded-xl cursor-pointer
          transition-all duration-300
          ${isDragging
            ? 'border-accent-blue bg-accent-blue/10'
            : 'border-white/10 hover:border-white/20 hover:bg-white/[0.02]'
          }
          ${uploading ? 'pointer-events-none opacity-60' : ''}
        `}
      >
        <input
          ref={fileRef}
          type="file"
          className="hidden"
          accept={ALLOWED_EXTENSIONS.join(',')}
          multiple
          onChange={(e) => {
            handleFiles(e.target.files)
            e.target.value = ''
          }}
        />

        {uploading ? (
          <>
            <div className="w-6 h-6 border-2 border-accent-blue border-t-transparent rounded-full animate-spin" />
            <span className="text-xs text-white/40">Uploading...</span>
          </>
        ) : (
          <>
            <FileUp size={20} className={isDragging ? 'text-accent-blue' : 'text-white/30'} />
            <span className="text-xs text-white/40 text-center">
              Drop Forensic Image
            </span>
          </>
        )}
      </div>

      {error && (
        <div className="flex items-center gap-2 mt-2 p-2 rounded-lg bg-risk-critical/10 text-risk-critical text-xs">
          <AlertCircle size={14} />
          {error}
        </div>
      )}

      {/* Multi-Upload Modal */}
      {pendingFiles && (
        <MultiUploadModal
          files={pendingFiles}
          onUpload={handleMultiUpload}
          onClose={() => setPendingFiles(null)}
        />
      )}
    </div>
  )
}

import React from 'react'
import { useApp } from '../context/AppContext'
import { LayoutDashboard, BarChart3, Brain, GitCompareArrows } from 'lucide-react'

const views = [
  { id: 'overview', label: 'Overview', icon: LayoutDashboard },
  { id: 'analytics', label: 'Analytics', icon: BarChart3 },
  { id: 'intelligence', label: 'Intelligence', icon: Brain },
]

export default function Header() {
  const { activeView, setActiveView, activeJob, caseCorrelationView, setCaseCorrelationView, cases } = useApp()

  const correlationCase = caseCorrelationView
    ? cases.find(c => c.case_id === caseCorrelationView)
    : null

  const handleTabClick = (id) => {
    if (caseCorrelationView) setCaseCorrelationView(null)
    setActiveView(id)
  }

  return (
    <header className="h-14 flex items-center justify-between px-6 border-b border-white/[0.06] bg-black/50 backdrop-blur-xl">
      <div className="flex items-center gap-3">
        <div className="flex items-center gap-1">
          {views.map(({ id, label, icon: Icon }) => (
            <button
              key={id}
              onClick={() => handleTabClick(id)}
              className={`
                flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200
                ${activeView === id && !caseCorrelationView
                  ? 'bg-white/[0.08] text-white'
                  : 'text-white/40 hover:text-white/70 hover:bg-white/[0.03]'
                }
              `}
            >
              <Icon size={16} />
              {label}
            </button>
          ))}
        </div>

        {correlationCase && (
          <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-cyan-500/10 text-cyan-400 text-sm font-medium border border-cyan-500/20">
            <GitCompareArrows size={14} />
            <span>Fallkorrelation</span>
            <span className="text-white/30 mx-0.5">|</span>
            <span className="text-white/70 text-xs">{correlationCase.case_name}</span>
          </div>
        )}
      </div>

      {activeJob && !caseCorrelationView && (
        <div className="flex items-center gap-3 text-sm">
          <span className="text-white/30 font-mono text-xs">
            {activeJob.job_id}
          </span>
          {activeJob.status === 'processing' && (
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-accent-blue animate-pulse" />
              <span className="text-accent-blue">{activeJob.progress}%</span>
            </div>
          )}
          {activeJob.status === 'completed' && (
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-accent-green" />
              <span className="text-accent-green">Abgeschlossen</span>
            </div>
          )}
          {activeJob.status === 'failed' && (
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-risk-critical" />
              <span className="text-risk-critical">Fehlgeschlagen</span>
            </div>
          )}
        </div>
      )}
    </header>
  )
}

