import { useState, useEffect } from 'react'

export function useLocalStorage(key, initialValue) {
  const [value, setValue] = useState(() => {
    try {
      const stored = localStorage.getItem(key)
      return stored ? JSON.parse(stored) : initialValue
    } catch {
      return initialValue
    }
  })

  useEffect(() => {
    try {
      localStorage.setItem(key, JSON.stringify(value))
    } catch {
      // quota exceeded or private browsing
    }
  }, [key, value])

  return [value, setValue]
}

import React from 'react'
import { useApp } from '../context/AppContext'
import { Check, Loader2, Circle } from 'lucide-react'

const PIPELINE_STAGES = [
  { id: 'detect',     label: 'File Detection',    range: [0, 8] },
  { id: 'uac',        label: 'UAC Processing',    range: [8, 18] },
  { id: 'logparse',   label: 'Log Parsing',       range: [18, 30] },
  { id: 'dissect',    label: 'Dissect Parser',    range: [30, 42] },
  { id: 'sleuthkit',  label: 'Sleuth Kit',        range: [42, 54] },
  { id: 'normalize',  label: 'Normalization',     range: [54, 66] },
  { id: 'anomaly',    label: 'Anomaly Detection', range: [66, 76] },
  { id: 'mitre',      label: 'MITRE ATT&CK',     range: [76, 84] },
  { id: 'preprocess', label: 'AI Preprocessing',  range: [84, 92] },
  { id: 'export',     label: 'Export',            range: [92, 100] },
]

function getStageStatus(stage, progress) {
  if (progress >= stage.range[1]) return 'done'
  if (progress >= stage.range[0]) return 'active'
  return 'pending'
}

export default function StatusMonitor() {
  const { activeJob } = useApp()

  if (!activeJob || activeJob.status !== 'processing') return null

  const progress = activeJob.progress || 0

  return (
    <div className="glass p-4 mx-3 mb-3">
      <div className="flex items-center justify-between mb-3">
        <span className="text-xs font-medium text-white/60">Pipeline</span>
        <span className="text-xs font-mono text-accent-blue">{progress}%</span>
      </div>

      {/* Progress bar */}
      <div className="h-1 bg-white/[0.06] rounded-full mb-3 overflow-hidden">
        <div
          className="h-full bg-gradient-to-r from-accent-blue to-accent-cyan rounded-full transition-all duration-500"
          style={{ width: `${progress}%` }}
        />
      </div>

      {/* Stages */}
      <div className="space-y-1.5">
        {PIPELINE_STAGES.map((stage) => {
          const status = getStageStatus(stage, progress)
          return (
            <div key={stage.id} className="flex items-center gap-2">
              {status === 'done' && <Check size={12} className="text-accent-green flex-shrink-0" />}
              {status === 'active' && <Loader2 size={12} className="text-accent-blue animate-spin flex-shrink-0" />}
              {status === 'pending' && <Circle size={12} className="text-white/15 flex-shrink-0" />}
              <span className={`text-[11px] ${
                status === 'active' ? 'text-accent-blue' :
                status === 'done' ? 'text-white/50' : 'text-white/20'
              }`}>
                {stage.label}
              </span>
            </div>
          )
        })}
      </div>
    </div>
  )
}

import React, { useState } from 'react'
import { useApp } from '../../context/AppContext'
import { exportPdf } from '../../api/backend'
import LLMReportView from './LLMReportView'
import FindingsCards from './FindingsCards'
import IOCList from './IOCList'
import EvidenceIntegrity from './EvidenceIntegrity'
import RiskBadge from '../RiskBadge'
import { formatTimestamp } from '../../utils/formatters'
import { FileText, AlertTriangle, Activity, Clock, Download, Loader2 } from 'lucide-react'

export default function OverviewPanel() {
  const { activeJob, getCaseForJob } = useApp()
  const [reportOpen, setReportOpen] = useState(false)
  const [pdfLoading, setPdfLoading] = useState(false)
  const [pdfError, setPdfError] = useState(null)

  const data = activeJob?.data
  if (!data) return null

  const summary = data.summary || {}
  const anomalies = data.anomalies || []
  const preprocessed = data.preprocessed || {}
  const indicators = preprocessed.indicators || {}

  const overallRisk = anomalies.length > 0
    ? (Math.max(...anomalies.map(a => a.anomaly_score || 0)) >= 0.8 ? 'critical'
      : Math.max(...anomalies.map(a => a.anomaly_score || 0)) >= 0.6 ? 'high'
      : Math.max(...anomalies.map(a => a.anomaly_score || 0)) >= 0.4 ? 'medium' : 'low')
    : 'info'

  return (
    <div className="space-y-6">
      {/* Top Stats */}
      <div className="grid grid-cols-4 gap-4">
        <StatCard
          icon={<Activity size={18} className="text-accent-blue" />}
          label="Total Events"
          value={summary.total_events || '—'}
        />
        <StatCard
          icon={<AlertTriangle size={18} className="text-risk-high" />}
          label="Anomalien"
          value={summary.anomalies_found || anomalies.length}
        />
        <StatCard
          icon={<Activity size={18} className="text-accent-cyan" />}
          label="IOCs"
          value={summary.iocs_identified || (indicators.ips?.length || 0) + (indicators.domains?.length || 0)}
        />
        <StatCard
          icon={<Clock size={18} className="text-white/40" />}
          label="Analysiert"
          value={formatTimestamp(summary.analysis_timestamp)}
          small
        />
      </div>

      {/* Risk Overview + Report Button */}
      <div className="glass-card flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div>
            <span className="text-xs text-white/40 block mb-1">Gesamtrisiko</span>
            <RiskBadge level={overallRisk} size="md" />
          </div>
          <div className="h-8 w-px bg-white/[0.06]" />
          <div>
            <span className="text-xs text-white/40 block mb-1">Input</span>
            <span className="text-sm font-mono text-white/70">{activeJob.filename}</span>
          </div>
          <div className="h-8 w-px bg-white/[0.06]" />
          <div>
            <span className="text-xs text-white/40 block mb-1">Typ</span>
            <span className="text-sm text-white/70">{activeJob.input_type}</span>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button
            onClick={async () => {
              setPdfLoading(true)
              setPdfError(null)
              try {
                const jobCase = getCaseForJob(activeJob.job_id)
                const caseInfo = jobCase ? {
                  case_name: jobCase.case_name,
                  case_number: jobCase.case_number,
                  analyst: jobCase.analyst,
                } : {}
                await exportPdf(activeJob.job_id, caseInfo)
              } catch (err) {
                setPdfError(err.message)
              } finally {
                setPdfLoading(false)
              }
            }}
            disabled={pdfLoading}
            className="flex items-center gap-2 px-4 py-2 rounded-xl bg-accent-purple/10 text-accent-purple hover:bg-accent-purple/20 transition-all text-sm font-medium disabled:opacity-50"
          >
            {pdfLoading ? <Loader2 size={16} className="animate-spin" /> : <Download size={16} />}
            PDF Export
          </button>
          <button
            onClick={() => setReportOpen(true)}
            className="flex items-center gap-2 px-4 py-2 rounded-xl bg-accent-blue/10 text-accent-blue hover:bg-accent-blue/20 transition-all text-sm font-medium"
          >
            <FileText size={16} />
            Vollständiger Report
          </button>
        </div>
      </div>
      {pdfError && (
        <div className="glass-card border border-risk-critical/20 text-risk-critical text-xs py-2">
          PDF-Fehler: {pdfError}
        </div>
      )}

      {/* Evidence Integrity */}
      <EvidenceIntegrity fileHash={activeJob.file_hash} jobId={activeJob.job_id} />

      {/* Key Findings */}
      {anomalies.length > 0 && (
        <div>
          <h3 className="text-sm font-medium text-white/50 mb-3 flex items-center gap-2">
            <AlertTriangle size={14} />
            Key Findings
          </h3>
          <FindingsCards anomalies={anomalies} />
        </div>
      )}

      {/* IOCs */}
      {Object.values(indicators).some(arr => arr?.length > 0) && (
        <div>
          <IOCList indicators={indicators} />
        </div>
      )}

      {/* Report Modal */}
      {reportOpen && (
        <LLMReportView
          report={data.report}
          anomalies={anomalies}
          indicators={indicators}
          summary={summary}
          onClose={() => setReportOpen(false)}
        />
      )}
    </div>
  )
}

function StatCard({ icon, label, value, small }) {
  return (
    <div className="glass-card flex items-center gap-3">
      <div className="w-10 h-10 rounded-xl bg-white/[0.03] flex items-center justify-center flex-shrink-0">
        {icon}
      </div>
      <div>
        <span className="text-[10px] text-white/30 uppercase tracking-wider block">{label}</span>
        <span className={`font-semibold text-white/80 ${small ? 'text-xs font-mono' : 'text-lg'}`}>
          {value}
        </span>
      </div>
    </div>
  )
}

import React, { useState, useMemo } from 'react'
import { useApp } from '../../context/AppContext'
import TimelineChart from './TimelineChart'
import ArtifactTaxonomy from './ArtifactTaxonomy'
import EventTable from './EventTable'
import { HardDrive, Layers, ChevronDown } from 'lucide-react'

export default function AnalyticsPanel() {
  const { activeJob } = useApp()
  const [selectedPartition, setSelectedPartition] = useState('all')
  const [partitionDropdownOpen, setPartitionDropdownOpen] = useState(false)

  const data = activeJob?.data
  if (!data) return null

  const allTimeline = data.normalized?.timeline || data.preprocessed?.timeline || []
  const anomalies   = data.anomalies || []

  // Partitions aus der Timeline oder aus der Summary ermitteln
  const partitions = useMemo(() => {
    const partitionMap = {}
    for (const event of allTimeline) {
      const p = event.partition || event.metadata?.partition
      if (p && !partitionMap[p]) {
        partitionMap[p] = {
          label:      p,
          filesystem: event.filesystem || event.metadata?.filesystem || '?',
          count:      0,
        }
      }
      if (p) partitionMap[p].count++
    }
    return Object.values(partitionMap)
  }, [allTimeline])

  const hasMultiplePartitions = partitions.length > 1

  // Timeline nach gewählter Partition filtern
  const timeline = useMemo(() => {
    if (selectedPartition === 'all' || !hasMultiplePartitions) return allTimeline
    return allTimeline.filter(e =>
      (e.partition || e.metadata?.partition) === selectedPartition
    )
  }, [allTimeline, selectedPartition, hasMultiplePartitions])

  // Gefilterte Anomalien für Chart
  const filteredAnomalies = useMemo(() => {
    if (selectedPartition === 'all' || !hasMultiplePartitions) return anomalies
    return anomalies.filter(e =>
      (e.partition || e.metadata?.partition) === selectedPartition
    )
  }, [anomalies, selectedPartition, hasMultiplePartitions])

  const selectedInfo = selectedPartition === 'all'
    ? null
    : partitions.find(p => p.label === selectedPartition)

  return (
    <div className="space-y-6">

      {/* ── Partition-Selector (nur bei Multi-Partition-Images) ── */}
      {hasMultiplePartitions && (
        <div className="glass-card">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 rounded-lg bg-accent-blue/10 flex items-center justify-center">
                <HardDrive size={14} className="text-accent-blue" />
              </div>
              <div>
                <span className="text-xs text-white/30 block">Partitionen erkannt</span>
                <span className="text-sm font-medium text-white/70">
                  {partitions.length} Partitionen im Image
                </span>
              </div>
            </div>

            {/* Dropdown */}
            <div className="relative">
              <button
                onClick={() => setPartitionDropdownOpen(prev => !prev)}
                className="flex items-center gap-2 px-3 py-2 rounded-lg bg-white/[0.05] hover:bg-white/[0.08] transition-all text-sm text-white/70 border border-white/[0.06]"
              >
                <Layers size={13} className="text-accent-blue" />
                <span>
                  {selectedPartition === 'all'
                    ? `Alle (${allTimeline.length} Events)`
                    : `${selectedPartition} · ${selectedInfo?.filesystem || '?'} · ${selectedInfo?.count ?? 0} Events`
                  }
                </span>
                <ChevronDown
                  size={12}
                  className={`text-white/30 transition-transform ${partitionDropdownOpen ? 'rotate-180' : ''}`}
                />
              </button>

              {partitionDropdownOpen && (
                <div
                  className="absolute right-0 top-full mt-1 w-72 rounded-xl bg-[#0d0d0d] border border-white/[0.08] shadow-2xl z-20 overflow-hidden"
                  onBlur={() => setPartitionDropdownOpen(false)}
                >
                  {/* Alle Partitionen Option */}
                  <button
                    onClick={() => { setSelectedPartition('all'); setPartitionDropdownOpen(false) }}
                    className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/[0.04] transition-colors text-left ${selectedPartition === 'all' ? 'bg-accent-blue/10' : ''}`}
                  >
                    <Layers size={13} className="text-accent-blue flex-shrink-0" />
                    <div>
                      <span className="text-sm text-white/70">Alle Partitionen</span>
                      <span className="text-xs text-white/30 block">{allTimeline.length} Events gesamt</span>
                    </div>
                  </button>

                  <div className="border-t border-white/[0.04]" />

                  {/* Einzelne Partitionen */}
                  {partitions.map(p => (
                    <button
                      key={p.label}
                      onClick={() => { setSelectedPartition(p.label); setPartitionDropdownOpen(false) }}
                      className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/[0.04] transition-colors text-left ${selectedPartition === p.label ? 'bg-accent-blue/10' : ''}`}
                    >
                      <HardDrive size={13} className="text-white/30 flex-shrink-0" />
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between gap-2">
                          <span className="text-sm font-mono text-white/70 truncate">{p.label}</span>
                          <span className="text-xs bg-white/[0.05] px-1.5 py-0.5 rounded-full text-white/30 flex-shrink-0">
                            {p.count} Events
                          </span>
                        </div>
                        <span className="text-xs text-accent-cyan">{p.filesystem}</span>
                      </div>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* Partition-Info-Chips */}
          <div className="flex flex-wrap gap-2 mt-3 pt-3 border-t border-white/[0.04]">
            {partitions.map(p => (
              <button
                key={p.label}
                onClick={() => setSelectedPartition(p.label === selectedPartition ? 'all' : p.label)}
                className={`flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs transition-all border ${
                  selectedPartition === p.label
                    ? 'bg-accent-blue/15 text-accent-blue border-accent-blue/30'
                    : 'bg-white/[0.03] text-white/40 border-white/[0.05] hover:bg-white/[0.06] hover:text-white/60'
                }`}
              >
                <HardDrive size={10} />
                <span className="font-mono">{p.label}</span>
                <span className="text-[9px] opacity-60">({p.filesystem})</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* ── Charts Row ── */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
        <div className="xl:col-span-2">
          <TimelineChart
            timeline={timeline}
            anomalies={filteredAnomalies}
          />
        </div>
        <div>
          <ArtifactTaxonomy timeline={timeline} />
        </div>
      </div>

      {/* ── Event Table ── */}
      <div>
        <div className="flex items-center justify-between mb-3">
          <h3 className="text-sm font-medium text-white/50">Event-Timeline</h3>
          {hasMultiplePartitions && selectedPartition !== 'all' && (
            <span className="text-xs text-accent-blue font-mono bg-accent-blue/10 px-2 py-1 rounded-lg">
              {selectedPartition} · {selectedInfo?.filesystem}
            </span>
          )}
        </div>
        <EventTable timeline={timeline} />
      </div>

    </div>
  )
}

import React, { useState, useMemo } from 'react'
import { useApp } from '../../context/AppContext'
import AnomalyList from './AnomalyList'
import AttackGraph from './AttackGraph'
import AgentAnalysisView from './AgentAnalysisView'
import { analyzeAnomaliesLocal } from '../../api/llm'
import { marked } from 'marked'
import DOMPurify from 'dompurify'
import {
  Sparkles, Loader2, Brain, Check,
  Shield, Target, Server, Network, AlertOctagon,
  Package, Key, ArrowRight,
} from 'lucide-react'

// ── MITRE Taktik-Kategorien für Täterinfrastruktur ────────────────────────────
const ATTACKER_INFRA_TACTICS = new Set([
  'Resource Development',
  'Command and Control',
  'Exfiltration',
  'Lateral Movement',
])

// Taktik → Icon + Farbe
const TACTIC_CONFIG = {
  'Resource Development':   { icon: Package,      color: 'text-accent-purple', bg: 'bg-accent-purple/10' },
  'Command and Control':    { icon: Network,      color: 'text-risk-critical', bg: 'bg-risk-critical/10' },
  'Exfiltration':           { icon: ArrowRight,   color: 'text-risk-high',     bg: 'bg-risk-high/10' },
  'Lateral Movement':       { icon: Server,       color: 'text-accent-blue',   bg: 'bg-accent-blue/10' },
  'Initial Access':         { icon: AlertOctagon, color: 'text-risk-high',     bg: 'bg-risk-high/10' },
  'Credential Access':      { icon: Key,          color: 'text-risk-medium',   bg: 'bg-risk-medium/10' },
  'Privilege Escalation':   { icon: Shield,       color: 'text-accent-orange', bg: 'bg-accent-orange/10' },
  'Defense Evasion':        { icon: Shield,       color: 'text-accent-cyan',   bg: 'bg-accent-cyan/10' },
  'Persistence':            { icon: Target,       color: 'text-accent-green',  bg: 'bg-accent-green/10' },
  'Execution':              { icon: Sparkles,     color: 'text-white/50',      bg: 'bg-white/[0.06]' },
  'Discovery':              { icon: Network,      color: 'text-white/50',      bg: 'bg-white/[0.06]' },
  'Impact':                 { icon: AlertOctagon, color: 'text-risk-critical', bg: 'bg-risk-critical/10' },
  'Reconnaissance':         { icon: Network,      color: 'text-accent-blue',   bg: 'bg-accent-blue/10' },
}

export default function IntelligencePanel() {
  const { activeJob, updateJobData } = useApp()
  const [llmLoading, setLlmLoading]   = useState(false)
  const [activeTab, setActiveTab]     = useState('threat') // 'threat' | 'attacker_infra'

  const data = activeJob?.data
  if (!data) return null

  const anomalies = data.anomalies || []

  // Gespeicherte Quick-Analyse aus Job-Daten laden
  const llmInsight = data.llmQuickAnalysis || null

  // MITRE Taktik-Zusammenfassung aus Anomalien berechnen
  const tacticSummary = useMemo(() => {
    const counts = {}
    for (const a of anomalies) {
      for (const tech of a.mitre_techniques || []) {
        counts[tech.tactic] = (counts[tech.tactic] || 0) + 1
      }
    }
    return Object.entries(counts)
      .map(([tactic, count]) => ({ tactic, count }))
      .sort((a, b) => b.count - a.count)
  }, [anomalies])

  // Täterinfrastruktur-Taktiken separieren
  const infraTactics  = tacticSummary.filter(t => ATTACKER_INFRA_TACTICS.has(t.tactic))
  const victimTactics = tacticSummary.filter(t => !ATTACKER_INFRA_TACTICS.has(t.tactic))

  // C2/Infra-Events extrahieren
  const infraEventTypes = new Set([
    'c2_beacon', 'c2_tool', 'vpn_connection', 'vpn_disconnect', 'vpn_ip_assigned',
    'dns_query', 'network_connect', 'suspicious_tool_installed', 'package_install',
    'reverse_shell_attempt',
  ])
  const infraAnomalies = useMemo(
    () => anomalies.filter(a =>
      infraEventTypes.has(a.event_type) ||
      (a.mitre_techniques || []).some(t => ATTACKER_INFRA_TACTICS.has(t.tactic))
    ),
    [anomalies]
  )

  const handleAnalyze = async () => {
    setLlmLoading(true)
    try {
      const result = await analyzeAnomaliesLocal(anomalies)
      updateJobData(activeJob.job_id, { llmQuickAnalysis: result })
    } catch (err) {
      updateJobData(activeJob.job_id, { llmQuickAnalysis: `**Fehler:** ${err.message}` })
    } finally {
      setLlmLoading(false)
    }
  }

  return (
    <div className="space-y-6">

      {/* ── Tab-Switcher: Threat Intelligence vs. Täterinfrastruktur ── */}
      {anomalies.length > 0 && (
        <div className="flex items-center gap-1 p-1 rounded-xl bg-white/[0.03] border border-white/[0.05] w-fit">
          <button
            onClick={() => setActiveTab('threat')}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'threat'
                ? 'bg-white/[0.08] text-white'
                : 'text-white/40 hover:text-white/60'
            }`}
          >
            <Brain size={14} className={activeTab === 'threat' ? 'text-accent-purple' : 'text-white/30'} />
            Threat Intelligence
          </button>
          <button
            onClick={() => setActiveTab('attacker_infra')}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'attacker_infra'
                ? 'bg-white/[0.08] text-white'
                : 'text-white/40 hover:text-white/60'
            }`}
          >
            <Target size={14} className={activeTab === 'attacker_infra' ? 'text-risk-critical' : 'text-white/30'} />
            Täterinfrastruktur
            {infraAnomalies.length > 0 && (
              <span className="text-[9px] bg-risk-critical/20 text-risk-critical px-1.5 py-0.5 rounded-full">
                {infraAnomalies.length}
              </span>
            )}
          </button>
        </div>
      )}

      {/* ══════════════════════════════════════════════════════════════════ */}
      {/* TAB: Threat Intelligence (Standard-Ansicht) */}
      {/* ══════════════════════════════════════════════════════════════════ */}
      {activeTab === 'threat' && (
        <>
          {/* LLM Quick Analysis */}
          {anomalies.length > 0 && (
            <div className="glass-card">
              <div className="flex items-center justify-between mb-3">
                <h3 className="text-sm font-medium text-white/50 flex items-center gap-2">
                  <Brain size={14} className="text-accent-purple" />
                  KI Threat Intelligence (Ollama)
                </h3>
                <button
                  onClick={handleAnalyze}
                  disabled={llmLoading}
                  className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium bg-accent-purple/10 text-accent-purple hover:bg-accent-purple/20 transition-all disabled:opacity-50"
                >
                  {llmLoading ? (
                    <Loader2 size={12} className="animate-spin" />
                  ) : llmInsight ? (
                    <Check size={12} />
                  ) : (
                    <Sparkles size={12} />
                  )}
                  {llmInsight ? 'Neu analysieren' : 'Analysieren'}
                </button>
              </div>

              {llmInsight && (
                <div
                  className="report-content text-sm"
                  dangerouslySetInnerHTML={{
                    __html: DOMPurify.sanitize(marked.parse(llmInsight))
                  }}
                />
              )}
              {!llmInsight && !llmLoading && (
                <p className="text-xs text-white/25">
                  Klicke "Analysieren" um eine lokale KI-Bedrohungsanalyse zu starten (Ollama).
                </p>
              )}
              {llmLoading && (
                <div className="flex items-center gap-3 py-4">
                  <div className="w-6 h-6 border-2 border-accent-purple border-t-transparent rounded-full animate-spin" />
                  <span className="text-xs text-white/30">Ollama analysiert Anomalien… (ca. 2–3 Min)</span>
                </div>
              )}
            </div>
          )}

          {/* Attack Kill Chain */}
          {anomalies.length > 0 && <AttackGraph anomalies={anomalies} />}

          {/* Multi-Agent Analysis */}
          {anomalies.length > 0 && <AgentAnalysisView />}

          {/* Anomaly List */}
          <AnomalyList anomalies={anomalies} />
        </>
      )}

      {/* ══════════════════════════════════════════════════════════════════ */}
      {/* TAB: Täterinfrastruktur-Analyse */}
      {/* ══════════════════════════════════════════════════════════════════ */}
      {activeTab === 'attacker_infra' && (
        <div className="space-y-6">

          {/* Erklärungstext */}
          <div className="glass-card border border-accent-blue/10 bg-accent-blue/[0.03]">
            <div className="flex items-start gap-3">
              <Target size={16} className="text-accent-blue flex-shrink-0 mt-0.5" />
              <div>
                <p className="text-sm font-medium text-white/70 mb-1">Täterinfrastruktur-Analyse</p>
                <p className="text-xs text-white/40 leading-relaxed">
                  Diese Ansicht fokussiert auf Hinweise die auf die <strong className="text-white/60">Infrastruktur des Angreifers</strong> hinweisen —
                  C2-Server, VPN-Nutzung, Tool-Staging, Lateral Movement und Exfiltration.
                  Im Gegensatz zur klassischen Opfer-Analyse wird hier die Perspektive des Täters eingenommen.
                </p>
              </div>
            </div>
          </div>

          {/* MITRE ATT&CK Kill Chain Coverage */}
          {tacticSummary.length > 0 && (
            <div className="glass-card">
              <h3 className="text-sm font-medium text-white/50 mb-4 flex items-center gap-2">
                <Shield size={14} className="text-accent-blue" />
                MITRE ATT&CK Kill Chain Coverage
              </h3>

              {/* Täterinfrastruktur-Taktiken */}
              {infraTactics.length > 0 && (
                <div className="mb-4">
                  <div className="text-[10px] text-risk-critical uppercase tracking-wider mb-2 flex items-center gap-1.5">
                    <Target size={9} />
                    Täterinfrastruktur-Taktiken
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    {infraTactics.map(({ tactic, count }) => {
                      const cfg = TACTIC_CONFIG[tactic] || { icon: Network, color: 'text-white/50', bg: 'bg-white/[0.05]' }
                      const Icon = cfg.icon
                      return (
                        <div key={tactic} className={`flex items-center gap-2.5 p-3 rounded-xl ${cfg.bg} border border-white/[0.04]`}>
                          <Icon size={14} className={cfg.color} />
                          <div className="min-w-0 flex-1">
                            <div className="text-xs font-medium text-white/70 truncate">{tactic}</div>
                            <div className={`text-[10px] ${cfg.color}`}>{count} Ereignis{count !== 1 ? 'se' : ''}</div>
                          </div>
                        </div>
                      )
                    })}
                  </div>
                </div>
              )}

              {/* Server-seitige Taktiken */}
              {victimTactics.length > 0 && (
                <div>
                  <div className="text-[10px] text-white/30 uppercase tracking-wider mb-2">Angriffs-Taktiken (Opfersystem)</div>
                  <div className="flex flex-wrap gap-2">
                    {victimTactics.map(({ tactic, count }) => {
                      const cfg = TACTIC_CONFIG[tactic] || { icon: Shield, color: 'text-white/40', bg: 'bg-white/[0.04]' }
                      const Icon = cfg.icon
                      return (
                        <div key={tactic} className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg ${cfg.bg}`}>
                          <Icon size={10} className={cfg.color} />
                          <span className="text-xs text-white/50">{tactic}</span>
                          <span className={`text-[9px] ${cfg.color} font-mono`}>{count}×</span>
                        </div>
                      )
                    })}
                  </div>
                </div>
              )}

              {tacticSummary.length === 0 && (
                <p className="text-xs text-white/25">Keine MITRE-Taktiken in den Anomalien erkannt.</p>
              )}
            </div>
          )}

          {/* Täterinfrastruktur-Events */}
          {infraAnomalies.length > 0 ? (
            <div className="glass-card">
              <h3 className="text-sm font-medium text-white/50 mb-3 flex items-center gap-2">
                <Network size={14} className="text-risk-critical" />
                Infrastruktur-Indikatoren
                <span className="text-[10px] bg-risk-critical/15 text-risk-critical px-2 py-0.5 rounded-full">
                  {infraAnomalies.length} Events
                </span>
              </h3>
              <div className="space-y-2">
                {infraAnomalies.slice(0, 50).map((event, idx) => (
                  <InfraEventRow key={idx} event={event} />
                ))}
                {infraAnomalies.length > 50 && (
                  <p className="text-xs text-white/25 text-center pt-2">
                    + {infraAnomalies.length - 50} weitere Events
                  </p>
                )}
              </div>
            </div>
          ) : (
            <div className="glass-card text-center py-8">
              <Target size={24} className="text-white/15 mx-auto mb-2" />
              <p className="text-sm text-white/30">Keine Täterinfrastruktur-Indikatoren erkannt.</p>
              <p className="text-xs text-white/20 mt-1">
                Für diese Analyse werden C2-Beacons, VPN-Events, Tool-Staging und Lateral-Movement-Events ausgewertet.
              </p>
            </div>
          )}

          {/* Alle Anomalien (gefiltert nach MITRE-Infra-Taktiken) */}
          <AnomalyList anomalies={anomalies} filterTactics={ATTACKER_INFRA_TACTICS} />

        </div>
      )}

    </div>
  )
}

// ── Einzelne Infra-Event-Zeile ─────────────────────────────────────────────────

function InfraEventRow({ event }) {
  const [expanded, setExpanded] = useState(false)

  const techniques = event.mitre_techniques || []
  const src_ip  = event.src_ip  || event.metadata?.src_ip  || event.client_ip || ''
  const dst_ip  = event.dst_ip  || event.metadata?.dst_ip  || ''
  const user    = event.user    || event.metadata?.user    || ''
  const port    = event.dst_port || event.metadata?.dst_port || ''

  // Event-Typ → Farbe
  const TYPE_COLORS = {
    'c2_beacon':               'text-risk-critical',
    'reverse_shell_attempt':   'text-risk-critical',
    'c2_tool':                 'text-risk-high',
    'vpn_connection':          'text-accent-blue',
    'suspicious_tool_installed': 'text-risk-high',
    'data_exfiltration':       'text-risk-high',
    'lateral_movement':        'text-accent-purple',
  }
  const typeColor = TYPE_COLORS[event.event_type] || 'text-white/40'

  return (
    <div
      className="rounded-xl bg-white/[0.02] border border-white/[0.04] hover:border-white/[0.07] transition-all cursor-pointer"
      onClick={() => setExpanded(prev => !prev)}
    >
      <div className="flex items-center gap-3 px-3 py-2.5">
        {/* Event-Typ */}
        <span className={`text-xs font-mono font-medium ${typeColor} flex-shrink-0 w-48 truncate`}>
          {event.event_type}
        </span>

        {/* Beschreibung */}
        <span className="text-xs text-white/50 flex-1 truncate">
          {event.message || event.description || '—'}
        </span>

        {/* IPs */}
        {(src_ip || dst_ip) && (
          <span className="text-[10px] font-mono text-white/25 flex-shrink-0">
            {src_ip}{src_ip && dst_ip ? ' → ' : ''}{dst_ip}{port ? `:${port}` : ''}
          </span>
        )}

        {/* MITRE-Badges */}
        {techniques.length > 0 && (
          <div className="flex items-center gap-1 flex-shrink-0">
            {techniques.slice(0, 2).map((t, i) => (
              <span key={i} className="text-[9px] bg-risk-critical/10 text-risk-critical px-1.5 py-0.5 rounded font-mono">
                {t.id}
              </span>
            ))}
            {techniques.length > 2 && (
              <span className="text-[9px] text-white/25">+{techniques.length - 2}</span>
            )}
          </div>
        )}
      </div>

      {/* Expandiertes Detail */}
      {expanded && (
        <div className="border-t border-white/[0.04] px-3 py-3 space-y-2">
          {/* Alle MITRE-Techniken */}
          {techniques.length > 0 && (
            <div>
              <span className="text-[9px] text-white/25 uppercase tracking-wider block mb-1.5">MITRE ATT&CK</span>
              <div className="flex flex-wrap gap-1.5">
                {techniques.map((t, i) => (
                  <div key={i} className="flex items-center gap-1.5 bg-white/[0.03] rounded-lg px-2 py-1">
                    <span className="text-[10px] font-mono text-risk-critical">{t.id}</span>
                    <span className="text-[10px] text-white/50">{t.name}</span>
                    <span className="text-[9px] text-white/25">{t.tactic}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Metadaten */}
          <div className="grid grid-cols-3 gap-2 text-xs">
            {src_ip  && <InfoCell label="Quell-IP"    value={src_ip} />}
            {dst_ip  && <InfoCell label="Ziel-IP"     value={dst_ip} />}
            {port    && <InfoCell label="Port"        value={port} />}
            {user    && <InfoCell label="Nutzer"      value={user} />}
            {event.source && <InfoCell label="Quelle" value={event.source} />}
            {event.timestamp && <InfoCell label="Zeit" value={new Date(event.timestamp).toLocaleString('de-DE')} />}
          </div>
        </div>
      )}
    </div>
  )
}

function InfoCell({ label, value }) {
  return (
    <div>
      <span className="text-[9px] text-white/25 uppercase tracking-wider block">{label}</span>
      <span className="font-mono text-white/60 text-xs truncate block">{value}</span>
    </div>
  )
}

